/*
 * @name Add10RTMPV2
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param treeDataFiltered (INFOTABLE : HPMC.AddOn.RTMP.Tree.DS)
 * @param selectedTreeDataFiltered (INFOTABLE : HPMC.AddOn.RTMP.Tree.DS)
 * @return (INFOTABLE : HPMC.AddOn.RTMP.InputMachineParameters.DS)
 *
 * return 10 machine parameters from add 10 param
 */

var result;
var loggerBeginning = "[" + me.name + ":Add10RTMPV2]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to add 10 machine parameters from add 10 param");

		let Username = Resources["CurrentSessionInfo"].GetCurrentUser();

		result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.InputMachineParameters.DS"
		});
		let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.Table.ForDataTable.DS"
		});

		let maxAddedMachine = 10;

		let allSession = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
		let locationNameSession = allSession.locationName;
		let newTreeDataFiltered = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.Tree.DS"
		});
		for (let i = 0; i < treeDataFiltered.length; i++) {
			if (treeDataFiltered[i].parentName != "root") {
				newTreeDataFiltered.AddRow({
					parentID: treeDataFiltered[i].parentID, // STRING
					childName: treeDataFiltered[i].childName, // STRING
					childID: treeDataFiltered[i].childID, // STRING [Primary Key]
					parentName: treeDataFiltered[i].parentName, // STRING
					parameterDesc: treeDataFiltered[i].parameterDesc, // STRING
					childNameDisplay: treeDataFiltered[i].childNameDisplay // STRING
				});
			}
		}
        //logger.info(loggerBeginning + "Line 51 newTreeDataFiltered length is "+newTreeDataFiltered.length);

		let index = 0;
		if (selectedTreeDataFiltered.length > 0) {
       // logger.info(loggerBeginning + " Line 55 inside if selectedTreeDataFiltered.length > zero "+selectedTreeDataFiltered.length);

			for (let i = 0; i < newTreeDataFiltered.length; i++) {
				if (newTreeDataFiltered[i].parentName == selectedTreeDataFiltered.parentName) {
                //logger.info(loggerBeginning + " Line 59 inside if newTreeDataFiltered[i].parentName == selectedTreeDataFiltered.parentName newTreeDataFiltered[i].parentName is "+
                //newTreeDataFiltered[i].parentName+ " selectedTreeDataFiltered.parentName is  "+selectedTreeDataFiltered.parentName);

                    if (newTreeDataFiltered[i].childName == selectedTreeDataFiltered.childName) {
			        //logger.info(loggerBeginning + " Line 61 inside if newTreeDataFiltered[i].childName == selectedTreeDataFiltered.childName newTreeDataFiltered[i].childName is "+
                    //newTreeDataFiltered[i].childName+ " selectedTreeDataFiltered.childName is  "+selectedTreeDataFiltered.childName);

                        index = i;
						break;
					}
				}
			}
		}

		if (index > 0 && index < (newTreeDataFiltered.length - maxAddedMachine)) {
           //   logger.info(loggerBeginning + " Line 71 inside if index > 0 && index < (newTreeDataFiltered.length - maxAddedMachine"); Executed
			me.ChangeRTMPBatchToggleSessionFalse();
			me.ChangeRTMPBatchToggleSessionFalse2();
		} else if (index > 0 && index >= (newTreeDataFiltered.length - maxAddedMachine)) {
           //   logger.info(loggerBeginning + " Line 75 inside else if index > 0 && index >= (newTreeDataFiltered.length - maxAddedMachine");
			me.ChangeRTMPBatchToggleSessionFalse2();
			me.ChangeRTMPBatchToggleSessionTrue();
		} else if (index == 0 && newTreeDataFiltered.length < maxAddedMachine) {
          //    logger.info(loggerBeginning + " Line 79 inside else if index == 0 && newTreeDataFiltered.length < maxAddedMachine");
			me.ChangeRTMPBatchToggleSessionTrue();
			me.ChangeRTMPBatchToggleSessionTrue2();
		} else if (index == 0 && newTreeDataFiltered.length >= maxAddedMachine) {
           // logger.info(loggerBeginning + " Line 83 inside else if index == 0 && newTreeDataFiltered.length >= maxAddedMachine"); //Exected
			me.ChangeRTMPBatchToggleSessionFalse();
			me.ChangeRTMPBatchToggleSessionTrue2();
		} else {
            //logger.info(loggerBeginning + " Line 87 inside else ");
			me.ChangeRTMPBatchToggleSessionTrue();
			me.ChangeRTMPBatchToggleSessionTrue2();
		}

		let counterMachineParameters = 0;
		for (let i = index; i < newTreeDataFiltered.length; i++) {
			if (counterMachineParameters < 5) {
            //  logger.info(loggerBeginning + " Line 95 Machine parameters are set after this Line is also set "+newTreeDataFiltered.length);

                data.AddRow({
					colorID: counterMachineParameters + 1, // NUMBER
					Location: locationNameSession, // STRING
					MachineId: newTreeDataFiltered[i].parentID, // STRING
					MachineName: newTreeDataFiltered[i].parentName, // STRING
					ParameterId: newTreeDataFiltered[i].childID, // STRING
					ParameterName: newTreeDataFiltered[i].childNameDisplay, // STRING
					Line: 'Line 1', // STRING
					Boundaries: false, // BOOLEAN
					BoundariesDisable: false, // BOOLEAN
					Color: 'color' + String(counterMachineParameters + 1), // STRING
					ParameterDesc: newTreeDataFiltered[i].parameterDesc, // STRING
					Username_Color: Username + '$color' + String(counterMachineParameters + 1) // STRING [Primary Key]
				});
                // logger.info(loggerBeginning + " Line 114 newTreeDataFiltered length is "+ newTreeDataFiltered.length); //Executing and returning value as 52
			} else {
                 //  logger.info(loggerBeginning + " Line 116 in else block if machineparameters > 5 ");
					data.AddRow({
					colorID: counterMachineParameters + 1, // NUMBER
					Location: locationNameSession, // STRING
					MachineId: newTreeDataFiltered[i].parentID, // STRING
					MachineName: newTreeDataFiltered[i].parentName, // STRING
					ParameterId: newTreeDataFiltered[i].childID, // STRING
					ParameterName: newTreeDataFiltered[i].childNameDisplay, // STRING
					Line: 'Line 2', // STRING
					Boundaries: false, // BOOLEAN
					BoundariesDisable: false, // BOOLEAN
					Color: 'color' + String(counterMachineParameters + 1), // STRING
					ParameterDesc: newTreeDataFiltered[i].parameterDesc, // STRING
					Username_Color: Username + '$color' + String(counterMachineParameters + 1) // STRING [Primary Key]
				});
			}
			counterMachineParameters += 1;
			if (counterMachineParameters == maxAddedMachine) {
				break;
			}
		}

		if (data.length != 0 && data.length < 10) {
         //   logger.info(loggerBeginning + " Line 126 in if block this is not good it adds null values to mschine parameters ");
			for (let i = data.length; i < 10; i++) {
				data.AddRow({
					colorID: i + 1, // NUMBER
					Location: "", // STRING
					MachineId: "", // STRING
					MachineName: "", // STRING
					ParameterId: "", // STRING
					ParameterName: "", // STRING
					Line: "", // STRING
					Boundaries: false, // BOOLEAN
					BoundariesDisable: false, // BOOLEAN
					Color: "", // STRING
					ParameterDesc: "", // STRING
					Username_Color: Username + "$color" + String(i + 1) // STRING [Primary Key]
				});
			}
		}

		if (data.length == 0) {
           // logger.info(loggerBeginning + " Line 159 in if block data.length == 0");
			result.AddRow({
				indicator: -99, // NUMBER
				MachineParameters: data // INFOTABLE
			});
		} else {
            //This block is executing as data is greater than 0 which is good
          //  logger.info(loggerBeginning + " Line 165 in else block if data.length not equal to 0 ");
			result.AddRow({
				indicator: 2, // NUMBER   //Originaly it was 2 changed to 1 so that it will go  UpdateMachineParametersV2 in if block
				MachineParameters: data // INFOTABLE
			});
		}
		//logger.info(loggerBeginning + "MachineParameters length is "+MachineParameters.length);
		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		let dataForAddParam = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.InputMachineParameters.DS"
		});
		result = dataForAddParam;
		logger.error(loggerBeginning + " " + "Cannot add 10 machine parameters from add 10 param" + " " + "Exception : " + error);
	}
}());


/*
 * @name AddNext10RTMPV2
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param treeDataFiltered (INFOTABLE : HPMC.AddOn.RTMP.Tree.DS)
 * @return (INFOTABLE : HPMC.AddOn.RTMP.InputMachineParameters.DS)
 *
 * return 10 machine parameters from next 10 param
 */

var result;
var loggerBeginning = "[" + me.name + ":AddNext10RTMPDataTable]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to add 10 machine parameters from next 10 param");

		result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.InputMachineParameters.DS"
		});
		let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.Table.ForDataTable.DS"
		});
		let maxAddedMachine = 10;
		let allSession = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
		let locationNameSession = allSession.locationName;
		let allData = allSession.MachineParameters;
		let machineNameFirst = allData[0].MachineName;
		let parameterName = allData[0].ParameterName;
		let dataLength = 0;
		for (let i = 0; i < allData.length; i++) {
			if (allData[i].MachineId != "") {
				dataLength += 1;
			}
		}
		let Username = Resources["CurrentSessionInfo"].GetCurrentUser();
		let newTreeDataFiltered = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.Tree.DS"
		});
		for (let i = 0; i < treeDataFiltered.length; i++) {
			if (treeDataFiltered[i].parentName != "root") {
				newTreeDataFiltered.AddRow({
					parentID: treeDataFiltered[i].parentID, // STRING
					childName: treeDataFiltered[i].childName, // STRING
					childID: treeDataFiltered[i].childID, // STRING [Primary Key]
					parentName: treeDataFiltered[i].parentName, // STRING
					parameterDesc: treeDataFiltered[i].parameterDesc, // STRING
					childNameDisplay: treeDataFiltered[i].childNameDisplay // STRING
				});
			}
		}
		let index = 0;
		for (let i = 0; i < newTreeDataFiltered.length; i++) {
			if (newTreeDataFiltered[i].parentName == machineNameFirst) {
				if (newTreeDataFiltered[i].childName == parameterName) {
					index = i;
					break;
				}
			}
		}

		let firstIndexMachine = maxAddedMachine;
		if (dataLength < maxAddedMachine) {
			firstIndexMachine = dataLength;
		}
		index += firstIndexMachine;

		if (index > 0 && index < (newTreeDataFiltered.length - maxAddedMachine)) {
			me.ChangeRTMPBatchToggleSessionFalse();
			me.ChangeRTMPBatchToggleSessionFalse2();
		} else if (index >= (newTreeDataFiltered.length - maxAddedMachine)) {
			me.ChangeRTMPBatchToggleSessionFalse2();
			me.ChangeRTMPBatchToggleSessionTrue();
		} else if (index == 0) {
			me.ChangeRTMPBatchToggleSessionFalse();
			me.ChangeRTMPBatchToggleSessionTrue2();
		}

		let counterMachineParameters = 0;
		for (let i = index; i < newTreeDataFiltered.length; i++) {
			if (counterMachineParameters < 5) {
				data.AddRow({
					colorID: counterMachineParameters + 1, // NUMBER
					Location: locationNameSession, // STRING
					MachineId: newTreeDataFiltered[i].parentID, // STRING
					MachineName: newTreeDataFiltered[i].parentName, // STRING
					ParameterId: newTreeDataFiltered[i].childID, // STRING
					ParameterName: newTreeDataFiltered[i].childNameDisplay, // STRING
					Line: "Line 1", // STRING
					Boundaries: false, // BOOLEAN
					BoundariesDisable: false, // BOOLEAN
					Color: "color" + String(counterMachineParameters + 1), // STRING
					ParameterDesc: newTreeDataFiltered[i].parameterDesc, // STRING
					Username_Color: Username + "$color" + String(counterMachineParameters + 1) // STRING [Primary Key]
				});
			} else {
				data.AddRow({
					colorID: counterMachineParameters + 1, // NUMBER
					Location: locationNameSession, // STRING
					MachineId: newTreeDataFiltered[i].parentID, // STRING
					MachineName: newTreeDataFiltered[i].parentName, // STRING
					ParameterId: newTreeDataFiltered[i].childID, // STRING
					ParameterName: newTreeDataFiltered[i].childNameDisplay, // STRING
					Line: "Line 2", // STRING
					Boundaries: false, // BOOLEAN
					BoundariesDisable: false, // BOOLEAN
					Color: "color" + String(counterMachineParameters + 1), // STRING
					ParameterDesc: newTreeDataFiltered[i].parameterDesc, // STRING
					Username_Color: Username + "$color" + String(counterMachineParameters + 1) // STRING [Primary Key]
				});
			}
			counterMachineParameters += 1;
			if (counterMachineParameters == maxAddedMachine) {
				break;
			}
		}

		if (data.length != 0 && data.length < 10) {
			for (let i = data.length; i < 10; i++) {
				data.AddRow({
					colorID: i + 1, // NUMBER
					Location: "", // STRING
					MachineId: "", // STRING
					MachineName: "", // STRING
					ParameterId: "", // STRING
					ParameterName: "", // STRING
					Line: "", // STRING
					Boundaries: false, // BOOLEAN
					BoundariesDisable: false, // BOOLEAN
					Color: "", // STRING
					ParameterDesc: "", // STRING
					Username_Color: Username + "$color" + String(i + 1) // STRING [Primary Key]
				});
			}
		}

		if (data.length == 0) {
			result.AddRow({
				indicator: -99, // NUMBER
				MachineParameters: data // INFOTABLE
			});
		} else {
			result.AddRow({
				indicator: 3, // NUMBER
				MachineParameters: data // INFOTABLE
			});
		}

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		let dataForAddParam = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.InputMachineParameters.DS"
		});
		result = dataForAddParam;
		logger.error(loggerBeginning + " " + "Cannot add 10 machine parameters from next 10 param" + " " + "Exception : " + error);
	}
}());


