/*
 * @name AddRTMPV2
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param MachineName (STRING)
 * @param ParameterName (STRING)
 * @param MachineId (STRING)
 * @param ParameterId (STRING)
 * @param ParameterDescription (STRING)
 * @return (INFOTABLE : HPMC.AddOn.RTMP.InputMachineParameters.DS)
 *
 * return new machine parameter selected
 */

var result;
var loggerBeginning = "[" + me.name + ":AddRTMPDataTable]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to add new machine parameter");

		let Username = Resources["CurrentSessionInfo"].GetCurrentUser();
		result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.InputMachineParameters.DS"
		});
		let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.Table.ForDataTable.DS"
		});

		if (MachineName != "" && MachineName != undefined && ParameterName != "" && ParameterName != undefined) {
            logger.info(loggerBeginning + "Line 34 inside if MachineName!=null");  //Executed
			let allSession = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
			let locationNameSession = allSession.locationName;
			let allData = allSession.MachineParameters;
			let isParamaterSame = false;

			for (let i = 0; i < allData.length; i++) {
				if (allData[i].MachineId == MachineId) {
                      logger.info(loggerBeginning + "Line 42");
					if (allData[i].ParameterId == ParameterId) {
                        logger.info(loggerBeginning + "Line 44");
						isParamaterSame = true;
						break;
					}
				}
			}

			if (isParamaterSame == false) {
                logger.info(loggerBeginning + "Line 52"); //Executed
				let colorstatus = [false, false, false, false, false, false, false, false, false, false];
				for (let i = 0; i < allData.length; i++) {
					for (let j = 1; j < 11; j++) {
						if (allData[i].Color == "color" + j.toString()) {
                            logger.info(loggerBeginning + "Line 57");
							colorstatus[j - 1] = true;
						}
					}
				}

				let line = "NULL";
				let line1Count = 0;
				let line2Count = 0;
				for (let i = 0; i < allData.length; i++) {
					if (allData[i].Line == "Line 1") {
                        logger.info(loggerBeginning + "Line 68");
						line1Count += 1;
					} else if (allData[i].Line == "Line 2") {
                        logger.info(loggerBeginning + "Line 71");
						line2Count += 1;
					}
				}

				if (line1Count < 5) {
                    logger.info(loggerBeginning + "Line 77");  //Executed
					line = "Line 1";
				} else {
                    logger.info(loggerBeginning + "Line 80");
					line = "Line 2";
				}

				let index = 1;
				for (let i = 0; i < 10; i++) {
					if (colorstatus[i] == false) {
                        logger.info(loggerBeginning + "Line 87"); //Executed
						break;
					} else {
                        logger.info(loggerBeginning + "Line 90");
						index += 1;
					}
				}

				let boundariesCount = 0;
				if (line == "Line 1") {
                    logger.info(loggerBeginning + "Line 97"); //Executed
					for (let i = 0; i < allData.length; i++) {
						if (allData[i].Line == "Line 1") {
                            logger.info(loggerBeginning + "Line 100");
							if (allData[i].Boundaries == true) {
                                logger.info(loggerBeginning + "Line 102");
								boundariesCount += 1;
							}
						}
					}
				} else if (line == "Line 2") {
                    logger.info(loggerBeginning + "Line 108");
					for (let i = 0; i < allData.length; i++) {
						if (allData[i].Line == "Line 2") {
                            logger.info(loggerBeginning + "Line 111");
							if (allData[i].Boundaries == true) {
                                logger.info(loggerBeginning + "Line 113");
								boundariesCount += 1;
							}
						}
					}
				}

				let BoundariesDisable = false;
				if (boundariesCount > 0) {
                    logger.info(loggerBeginning + "Line 122");
					BoundariesDisable = true;
				}

				if (index < 11) {
                    logger.info(loggerBeginning + "Line 127"); //Executed
					data.AddRow({
						colorID: index,
						Location: locationNameSession, // STRING
						MachineName: MachineName, // STRING
						MachineId: MachineId,
						ParameterId: ParameterId,
						ParameterName: ParameterName, // STRING
						Line: line, // STRING
						Color: "color" + index, // STRING [Primary Key],
						Boundaries: false,
						BoundariesDisable: BoundariesDisable,
						ParameterDesc: ParameterDescription, // STRING
						Username_Color: Username + "$color" + index,
					});
					result.AddRow({
						indicator: 1, // NUMBER
						MachineParameters: data // INFOTABLE
					});
             //          logger.info(loggerBeginning + "Line 146 Machine parameter length is "+MachineParameters.length); //Executed
				} else {
              		logger.info(loggerBeginning + "Line 147");
					result.AddRow({ // parameters data are already 10 parameters
						indicator: -79, // NUMBER
						MachineParameters: data // INFOTABLE
					});
				}
			} else {
			   logger.info(loggerBeginning + "Line 154");
			   result.AddRow({ // parameter is already in MachineParameters
					indicator: -89, // NUMBER
					MachineParameters: data // INFOTABLE
				});
			}
		} else {
			logger.info(loggerBeginning + "Line 161");
			result.AddRow({ // input from tree is false
				indicator: -99, // NUMBER
				MachineParameters: data // INFOTABLE
			});
		}

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		let dataForAddParam = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.InputMachineParameters.DS"
		});
		result = dataForAddParam;
		logger.error(loggerBeginning + " " + "Cannot add new machine parameter" + " " + "Exception : " + error);
	}
}());


