/*
 * @name ChangeMashupLineChartV2
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @return (STRING)
 *
 * return machup name for line chart session
 */

var result;
var loggerBeginning = "[" + me.name + ":ChangeMashupLineChartV2]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to get mashup name for line chart");

		let session = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
		let dataSession = session.MachineParameters;
		let allData = dataSession;
		//let allData = dataSession.Rows;

		//logger.info(loggerBeginning + " allData: " + JSON.stringify(allData));
		//logger.info(loggerBeginning + " Number of records in allData: " + allData.length);

		let isThereDifferentLine = false;
		let countLine = 0;
		let lastLine = "";

        for (let i = 0; i < allData.length; i++) {
			if (countLine == 0) {
        		if (allData[i].Line == "Line 1") {
					countLine += 1;
					lastLine = "Line 1";
					continue;
				}
				if (allData[i].Line == "Line 2") {
        			countLine += 1;
					lastLine = "Line 2";
					continue;
				}
			} else if (countLine == 1) {
				if (allData[i].Line == "Line 1" && lastLine == "Line 2") {
        			countLine += 1;
					lastLine = "Line 1";
					break;
				}
				if (allData[i].Line == "Line 2" && lastLine == "Line 1") {
					countLine += 1;
					lastLine = "Line 2";
					break;
				}
			}
		}

		if (countLine == 2) {
        	result = "HPMC.AddOn.RTMP.Contained.Two.LineChart.V2.MU";
            	logger.info(loggerBeginning + "Two line chart "+result);
		} else if (countLine == 1) {
        	result = "HPMC.AddOn.RTMP.Contained.One.LineChart.V2.MU"; 
          //  result = "HPMC.AddOn.RTMP.Contained.One.LineChart.V2.MU_DUPLICATE"; // Changed on 3 Marh/2025 to test grid Original name was HPMC.AddOn.RTMP.Contained.One.LineChart.V2.MU
            logger.info(loggerBeginning + " one line chart "+result);
		} else {
        	result = "HPMC.AddOn.RTMP.Contained.Zero.LineChart.V2.MU"; //Changed to HPMC.AddOn.RTMP.Contained.One.LineChart.V2.MU previous it was HPMC.AddOn.RTMP.Contained.Zero.LineChart.V2.MU
           	logger.info(loggerBeginning + "in else "+result);

        }

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot get mashup name for line chart" + " " + "Exception : " + error);
	}
}());


