/*
 * @name CheckMinuteRange
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param timeCategory (STRING)
 * @param startDate (DATETIME)
 * @param endDate (DATETIME)
 * @return (BOOLEAN)
 *
 * return boolean whether date range of custom time RTMP is out of limit
 */

var result;
var loggerBeginning = "[" + me.name + ":CheckMinuteRange]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to check whether date range of custom time RTMP is out of limit");

		let Username = Resources["CurrentSessionInfo"].GetCurrentUser();
		if (timeCategory == "Custom Time") {
			let tickMinute = Math.round(dateDifference(endDate, startDate) / 60000);
			let allSession = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
			let dataSession = allSession.MachineParameters;
			let allData = dataSession;
			let maxMinuteRange = tickMinute * allData.length;
			if (maxMinuteRange > me.maxMinuteRange) {
				result = false;
			} else {
				result = true;
			}
		} else {
			result = true;
		}

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot check whether date range of custom time RTMP is out of limit" + " " + "Exception : " + error);
	}
}());


