var result;
var loggerBeginning = "[" + me.name + ":DeleteRTMPV2]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to delete machine parameters selected from machine parameters session");

		let Username = Resources["CurrentSessionInfo"].GetCurrentUser();

		let allSession = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
		let dataSession = allSession.MachineParameters;
		let allData = dataSession;

		let newData = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.Table.ForDataTable.DS"
		});

		for (let i = 0; i < allData.length; i++) {
		 //   logger.info(loggerBeginning + "Line 33 Inside for username color is "+allData[i].Username_Color+" Color is "+Color);

            if (allData[i].Username_Color != Username + "$" + Color) {
		   //     logger.info(loggerBeginning + "Line 34 Inside if where color does not match");
				newData.AddRow({
					colorID: allData[i].colorID,
					Location: allData[i].Location, // STRING
					MachineName: allData[i].MachineName, // STRING
					ParameterName: allData[i].ParameterName, // STRING
					MachineId: allData[i].MachineId,
					ParameterId: allData[i].ParameterId,
					Line: allData[i].Line, // STRING
					Color: allData[i].Color, // STRING [Primary Key]
					Boundaries: allData[i].Boundaries,
					BoundariesDisable: allData[i].BoundariesDisable,
					ParameterDesc: allData[i].ParameterDesc, // STRING
					Username_Color: allData[i].Username_Color
				});
			} else {
                logger.info(loggerBeginning + "Line 50 Inside else where color match");
				newData.AddRow({
					colorID: allData[i].colorID,
					Location: "", // STRING
					MachineName: "", // STRING
					ParameterName: "", // STRING
					MachineId: "",
					ParameterId: "",
					Line: "", // STRING
					Color: "", // STRING [Primary Key]
					Boundaries: false,
					BoundariesDisable: false,
					ParameterDesc: "", // STRING
					Username_Color: allData[i].Username_Color
				});
			}
		}

		result = newData;

		try {
			if (Boundaries == true) {
                logger.info(loggerBeginning + "Line 72 inside if boundries = true ");
				let allData = newData;
				let updatedData = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
					infoTableName: "InfoTable",
					dataShapeName: "HPMC.AddOn.RTMP.Table.ForDataTable.DS"
				});
				for (let i = 0; i < allData.length; i++) {
                  logger.info(loggerBeginning + "Line 81 inside for  selectedLine.dropdown_value is "+selectedLine.dropdown_value);
                  logger.info(loggerBeginning + "Line 82 inside for  allData line is " +allData[i].Line);
					if (allData[i].Line == selectedLine.dropdown_value) {
                        logger.info(loggerBeginning + "Line 80 inside if when all data matches to selected data ");
						updatedData.AddRow({
							colorID: allData[i].colorID,
							Location: allData[i].Location, // STRING
							MachineName: allData[i].MachineName, // STRING
							ParameterName: allData[i].ParameterName, // STRING
							MachineId: allData[i].MachineId,
							ParameterId: allData[i].ParameterId,
							Line: allData[i].Line, // STRING
							Color: allData[i].Color, // STRING [Primary Key]
							Boundaries: false,
							BoundariesDisable: false,
							ParameterDesc: allData[i].ParameterDesc, // STRING
							Username_Color: allData[i].Username_Color
						});
					} else {
                        logger.info(loggerBeginning + "Line 96 inside else when all data does not tmatches to selected data ");
						updatedData.AddRow({
							colorID: allData[i].colorID,
							Location: allData[i].Location, // STRING
							MachineName: allData[i].MachineName, // STRING
							ParameterName: allData[i].ParameterName, // STRING
							MachineId: allData[i].MachineId,
							ParameterId: allData[i].ParameterId,
							Line: allData[i].Line, // STRING
							Color: allData[i].Color, // STRING [Primary Key]
							Boundaries: allData[i].Boundaries,
							BoundariesDisable: allData[i].BoundariesDisable,
							ParameterDesc: allData[i].ParameterDesc, // STRING
							Username_Color: allData[i].Username_Color
						});
					}
				}

				result = updatedData;
			}
		} catch (error) {
            logger.info(loggerBeginning + "inside catch error is  "+error);
			result = allData;
		}

		logger.info(loggerBeginning + "length of result data is "+allData.length);
		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot delete machine parameters selected from machine parameters session" + " " + "Exception : " + error);
	}
}());


