/*
 * @name GenerateChartDataV2
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param savedData (INFOTABLE : HPMC.AddOn.RTMP.MachineParametersData.DS)
 * @param originData (INFOTABLE : HPMC.AddOn.RTMP.MachineParametersData.DS)
 * @param colorID (NUMBER) 
 * @param startTime (DATETIME)
 * @param endTime (DATETIME)
 * @return (INFOTABLE : HPMC.AddOn.RTMP.MachineParametersData.DS)
 *
 * return machine parameter data per minute
 */

var result;
var loggerBeginning = "[" + me.name + ":GenerateChartDataV2]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to get machine parameter data per minute");

		let intervalMinutes = "'1 Minutes'";
		let allSession = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
		let intervalMinutesSession = allSession.intervalMinutes;
     //   logger.info(loggerBeginning + " Line 26 String color id is "+String(colorID)+" Normal color id is "+colorID);
		if (intervalMinutesSession != null || intervalMinutesSession != undefined || intervalMinutesSession != "") {
			intervalMinutes = intervalMinutesSession;
		}

		let Username = Resources["CurrentSessionInfo"].GetCurrentUser();
		let dataSession = allSession.MachineParameters;
     //   logger.info(loggerBeginning + "machine parameter length is "+dataSession.length);
		let allData = dataSession;
		let isThereColor = false;
		let isThereLine = false;
		let index = 99;
     //   logger.info(loggerBeginning + " Line 38 Color is "+allData.Color);
       // logger.info(loggerBeginning + " Line 39 colorID is  " +allData.colorID);

		for (let i = 0; i < allData.length; i++) {
		   //	if (allData[i].Color == "color" + String(colorID)) { 								// Original
           //  logger.info(loggerBeginning + " Line 42 Color is  " +allData[i].Color);
           //   logger.info(loggerBeginning + " Line 43 colorID is  " +allData[i].colorID);
            if (allData[i].Color == "color" + (i+1)) {          
          //  logger.info(loggerBeginning + "Line 5 Inside if where color matches  "+allData[i].Color+" colorId is  " +allData[i].colorID);
				isThereColor = true;
				isThereLine = true;
				index = i;
				break;
			}
             else{
            //    logger.info(loggerBeginning + "Line 52 Inside else where color does not matches  "+allData[i].Color+" colorId is  " +allData[i].colorID);
             //   logger.info(loggerBeginning + "Line 50 In else of color mismatch");
			}
		}

		let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.MachineParametersData.DS"
		});

		if (isThereColor == true && isThereLine == true && originData.length > 0) {
          // 	logger.info(loggerBeginning + " Line 62 we have color,line and data");
			let lastData = originData;
			if (savedData != undefined) {
            //     logger.info(loggerBeginning + "Line 65 we have savedData");

                if (savedData.length > 1 && savedData[0].machine_id == originData[0].machine_id) {
                 logger.info(loggerBeginning + "Line 68 we have savedData and it matches with machineID");
					let query = {
						"filters": {
							"type": "LE",
							"fieldName": "timestamp",
							"value": new Date(Number(startTime))
						}
					};
					let paramsQuery = {
						t: savedData /* INFOTABLE */ ,
						query: query /* QUERY */
					};
					let queryResult = Resources["InfoTableFunctions"].Query(paramsQuery);
					if (queryResult.length > 0) {
                  //      logger.info(loggerBeginning + "Line 82 queryResult.length > 0");
						let queryFirst = {
							"filters": {
								"type": "GE",
								"fieldName": "timestamp",
								"value": queryResult[queryResult.length - 1].timestamp
							}
						};
						let paramsQueryFirst = {
							t: savedData /* INFOTABLE */ ,
							query: queryFirst /* QUERY */
						};
						savedData = Resources["InfoTableFunctions"].Query(paramsQueryFirst);
					}
					let querySecond = {
						"filters": {
							"type": "NE",
							"fieldName": "parameter_name",
							"value": ""
						}
					};
					let paramsQuerySecond = {
						t: savedData /* INFOTABLE */ ,
						query: querySecond /* QUERY */
					};
					lastData = Resources["InfoTableFunctions"].Query(paramsQuerySecond);
					if (queryResult.length > 0) {

                       // logger.info(loggerBeginning + " Line 110 queryResult.length > 0");
						lastData[0].parameter_value = queryResult[queryResult.length - 1].parameter_value.toFixed(1);
					}
					lastData[0].timestamp = new Date(Number(startTime));
					let newDataDB = me.GetRealTimeMachineParameters({
						end_date: endTime /* DATETIME */ ,
						machine_id: allData[index].MachineId /* STRING */ ,
						parameter_id: parseInt(allData[index].ParameterId) /* NUMBER */ ,
						start_date: new Date(Number(lastData[lastData.length - 1].timestamp) + (10 * 1000)) /* DATETIME */ ,
						intervalMinutes: intervalMinutes
					});
					let newData = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
						infoTableName: "InfoTable",
						dataShapeName: "HPMC.AddOn.RTMP.MachineParametersData.DS"
					});
					for (let i = 0; i < newDataDB.length; i++) {
						newData.AddRow({
							machine_id: newDataDB[i].machine_id, // STRING
							parameter_id: newDataDB[i].parameter_id, // INTEGER
							parameter_name: newDataDB[i].parameter_name, // STRING
							parameter_value: newDataDB[i].parameter_value.toFixed(1), // NUMBER
							timestamp: newDataDB[i].timestamp // DATETIME
						});
					}
					let params2 = {
						t1: lastData /* INFOTABLE */ ,
						t2: newData /* INFOTABLE */
					};
					data = Resources["InfoTableFunctions"].Union(params2);
