 * @name GetConfiguredEmailsDetails
 * @date 24.06.2025
 * @author Atharva Mahabal
 * @param machineId (INFOTABLE : HPMC.AddOn.RTMP.Tree.DS)
 * @param parameterId
 * @param interval_Minutes
 * @param email
 * @param name
 * @param locId
 * @param upperBound
 * @param ucId
 * @param lowerBound
 * @return (INFOTABLE : HPMC.AddOn.RTMP.EmailDataFields.DS)
 *
 * return list of all configured emails 
 */

const DB_CONNECTOR= Things["HPMC.Core.Manager"].GetDatabaseConnector();
const now = new Date();
const startOfDay = new Date(now);
startOfDay.setHours(0, 0, 0, 0);
const endOfDay = new Date(now);
endOfDay.setHours(23, 59, 59, 999);

// Get machine data
let machineData = Things[DB_CONNECTOR].GetRealTimeMachineParametersNew({
    machine_id: machineId,
    parameter_id: parameterId,
    start_date: now,
    end_date: now,
    intervalMinutes: interval_Minutes
});

let machineRow = machineData.rows.length > 0 ? machineData.rows[0] : {};

// Create an InfoTable with the correct DataShape
let MachineInfo = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
    infoTableName: "EmailData",
    dataShapeName: "HPMC.AddOn.RTMP.EmailDataFields.DS"
});

//logger.info("GetConfiguredEmailsDetails inputs are LowerBound is "+inputLowerBound+"UpperBound is "+inputUpperBound);

// Add the new row
MachineInfo.AddRow({
    MachineId: machineId,        // STRING
    ParameterId: parameterId,    // STRING
    email: email,                // STRING
    UpperBound: inputUpperBound, // STRING
    LowerBound: inputLowerBound, // STRING
    parameterValue: machineRow.parameter_value || 0 // NUMBER
});


//logger.info("MachineInfo data : GetConfiguredEmailsDetails  " + JSON.stringify(MachineInfo.rows.toArray().map((r) => r.toJSON())));


// Step 1: Get the existing InfoTable property (initialize if empty)
let existingTable = (Things["HPMC.AddOn.RTMP.Manager"].MachineEmailAlertLog);


if (!existingTable || existingTable.rows.length === 0) {
    existingTable = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
        infoTableName: "EmailData",
        dataShapeName: "HPMC.AddOn.RTMP.EmailDataFields.DS"
    });
}

// Step 2: Simulate or generate new dynamic rows
let newRows = [];
let startNo = existingTable.rows.length + 1;  // Auto-increment starting from existing row count

for (let i = 0; i < MachineInfo.length; i++) {
    let machine = MachineInfo[i];  // Replace with your source

    newRows.push({
        No: startNo++,
        MachineId: machineId,
        ParameterId: parameterId,
        //  name: nameString,
        email: email,
        UpperBound: inputUpperBound,
        LowerBound: inputLowerBound,
        parameterValue: MachineInfo.parameterValue
    });
}

// Step 3: Add new rows to existing InfoTable
for (let i = 0; i < newRows.length; i++) {
    existingTable.AddRow(newRows[i]);
}

// Step 4: Save the updated table back to the Thing property
Things["HPMC.AddOn.RTMP.Manager"].MachineEmailAlertLog = existingTable;

result = existingTable;


