/*
 * @name GetExceedDataForExport
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param selectedItem (INFOTABLE : HPMC.AddOn.RTMP.Asset.Base.DS)
 * @param start_date (DATETIME)
 * @param end_date (DATETIME)
 * @param timezoneOffset (NUMBER)
 * @return (INFOTABLE : HPMC.AddOn.RTMP.ExceedData.Export.DS)
 *
 * return exceed data for export
 */

var result;
var loggerBeginning = "[" + me.name + ":GetExceedDataForExport]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to get exceed data for export");

		let machineIdList = "''";
		let machineIdArray = [""];
		for (let i = 0; i < selectedItem.length; i++) {
			if (machineIdArray.includes(selectedItem[i].machineId) == false) {
				machineIdList += ",'" + selectedItem[i].machineId + "'";
				machineIdArray.push(selectedItem[i].machineId);
			}
		}

		let data = Things["HPMC.AddOn.RTMP.Manager"].ExportExceedMachineParameterData({
			end_date: end_date /* DATETIME */ ,
			machineIdList: machineIdList /* STRING */ ,
			start_date: start_date /* DATETIME */
		});

		let exceedData = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.ExceedData.Export.DS"
		});

		for (let i = 0; i < data.length; i++) {
			let currentLanguage = Resources['CurrentSessionInfo'].GetCurrentUserLanguage();
			let title = Resources['RuntimeLocalizationFunctions'].GetEffectiveTokenForLanguage({
				language: currentLanguage /* STRING */ ,
				token: "HPMC.Parameter." + data[i].parameter_name.split(" ").join("") /* STRING */ ,
			});
			exceedData.AddRow({
				no: i + 1, // NUMBER
				machine_id: data[i].machine_id, // STRING
				parameter_name: title, // STRING
				parameter_value: data[i].parameter_value, // NUMBER
				pic: data[i].pic, // STRING
				exceed: data[i].exceed, // STRING
				bound_value: data[i].bound_value, // NUMBER
				message: data[i].message, // STRING
				timestamp: new Date(Number(data[i].timestamp) + (timezoneOffset * 60 * 60 * 1000)) // DATETIME
			});
		}

		result = exceedData;

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot get exceed data for export" + " " + "Exception : " + error);
	}
}());


/*
 * @name GetIntervalMinutes
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param timeCategory (STRING)
 * @param startDate (DATETIME)
 * @param endDate (DATETIME)
 * @return (STRING)
 *
 * return interval minutes based on time category
 */

var result;
var loggerBeginning = "[" + me.name + ":GetIntervalMinutes]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to get interval minutes based on time category");

		if (timeCategory == "last 30 minutes") {
			result = "'0.5 Minutes'";
		} else if (timeCategory == "last 1 hour") {
			result = "'1 Minutes'";
		} else if (timeCategory == "last 3 hours") {
			result = "'3 Minutes'";
		} else if (timeCategory == "last 6 hours") {
			result = "'6 Minutes'";
		} else if (timeCategory == "last 12 hours") {
			result = "'12 Minutes'";
		} else if (timeCategory == "last 24 hours") {
			result = "'24 Minutes'";
		} else {
			let tickMinute = Math.round(dateDifference(endDate, startDate) / (1000 * 60 * 60));
			if (tickMinute <= 0) {
				tickMinute = 1;
			}
			result = "'" + tickMinute + " Minutes'";
		}

		let params = {
			name: "intervalMinutes" /* STRING */ ,
			value: result /* STRING */
		};
		Resources["CurrentSessionInfo"].SetGlobalSessionStringValue(params);

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot get interval minutes based on time category" + " " + "Exception : " + error);
	}
}());


