/*
 * @name GetMachineParameterTree
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param selectedItems (INFOTABLE : HPMC.AddOn.RTMP.Asset.Base.DS)
 * @return (INFOTABLE : HPMC.AddOn.RTMP.Tree.DS)
 *
 * return machine parameters list
 */

var result;
var loggerBeginning = "[" + me.name + ":GetMachineParameterTree]";

(function() {
	"use strict";
	try {
		//logger.info(loggerBeginning + "Service to get machine parameters list");
		let parent = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
		infoTableName: "InfoTable",
		dataShapeName: "HPMC.AddOn.RTMP.Tree.DS"
		});

        let selectedMachines = "''";
        logger.info(loggerBeginning + "Line 25 above selected items GetMachineParameterTree");
       	for (let i = 0; i < selectedItems.length; i++) {
           selectedMachines += ",'" + selectedItems[i].machineId + "'";
		}

		let parameterList = me.GetMachineParameterList({
			machineIdList: selectedMachines /* STRING */
		});
        logger.info(loggerBeginning + "Line 32 below parameterList items GetMachineParameterTree");
		let lastMachineId = "";
		let lastMachineCaption = "";
        logger.info(loggerBeginning + "Line 35 below selected items GetMachineParameterTree");

		for (let i = 0; i < parameterList.length; i++) {
			if (lastMachineId != parameterList[i].machine_id) {
				lastMachineId = parameterList[i].machine_id;
				for (let j = 0; j < selectedItems.length; j++) {
					if (selectedItems[j].caption.split(" ")[0] == lastMachineId.slice(2, lastMachineId.length)) {
						lastMachineCaption = selectedItems[j].caption;
					}
				}
				parent.AddRow({
					"childID": lastMachineCaption,
					"childName": lastMachineCaption,
					"parentID": "root123",
					"parentName": "root",
					"parameterDesc": parameterList[i].parameter_desc,
					"childNameDisplay": lastMachineCaption
				});
			}
			let currentLanguage = Resources['CurrentSessionInfo'].GetCurrentUserLanguage();
			let title = Resources['RuntimeLocalizationFunctions'].GetEffectiveTokenForLanguage({
				language: currentLanguage /* STRING */ ,
				token: "HPMC.Parameter." + parameterList[i].parameter_name.split(" ").join("") /* STRING */ ,
			});
			parent.AddRow({
				"childID": String(parameterList[i].id),
				"childName": parameterList[i].parameter_name,
				"parentID": lastMachineId,
				"parentName": lastMachineCaption,
				"parameterDesc": parameterList[i].parameter_desc,
				"childNameDisplay": title
			});

		}
		result = parent;

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot get machine parameters list" + " " + "Exception : " + error);
	}
}());


/*
 * @name GetMachineParameterTreeFiltered
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param selectedItems (INFOTABLE : HPMC.AddOn.RTMP.Asset.Base.DS)
 * @param selectedParameter (INFOTABLE : HPMC.AddOn.RTMP.DropdownData.DS)
 * @return (INFOTABLE : HPMC.AddOn.RTMP.Tree.DS)
 *
 * return machine parameters list filtered
 */

var result;
var loggerBeginning = "[" + me.name + ":GetMachineParameterTreeFiltered]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to get machine parameters list filtered");

		let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.Tree.DS"
		});

		let machineIdList = [];
		let machineIdListAdded = [];
		for (let i = 0; i < treeData.length; i++) {
			for (let j = 0; j < selectedParameter.length; j++) {
				if (treeData[i].childName == selectedParameter[j].dropdown_value) {
					data.AddRow({
						parentID: treeData[i].parentID, // STRING
						childName: treeData[i].childName, // STRING
						childID: treeData[i].childID, // STRING [Primary Key]
						parentName: treeData[i].parentName, // STRING
						parameterDesc: treeData[i].parameterDesc, // STRING
						childNameDisplay: treeData[i].childNameDisplay // STRING
					});
					machineIdList.push(treeData[i].parentName);
				}
			}
		}

		for (let i = 0; i < treeData.length; i++) {
			if (treeData[i].parentName == "root") {
				if (machineIdList.includes(treeData[i].childName) == true) {
					if (machineIdListAdded.includes(treeData[i].childName) == false) {
						data.AddRow({
							parentID: treeData[i].parentID, // STRING
							childName: treeData[i].childName, // STRING
							childID: treeData[i].childID, // STRING [Primary Key]
							parentName: treeData[i].parentName, // STRING
							parameterDesc: treeData[i].parameterDesc, // STRING
							childNameDisplay: treeData[i].childNameDisplay // STRING
						});
						machineIdListAdded.push(treeData[i].childName);
					}
				}
			}
		}

		result = data;

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot get machine parameters list filtered" + " " + "Exception : " + error);
	}
}());


