        logger.info(loggerBeginning + "Line 26 interval Minute session is "+intervalMinutesSession);
		if (intervalMinutesSession != null || intervalMinutesSession != undefined || intervalMinutesSession != "") {
            logger.info(loggerBeginning + "Line 25 inside if where we get intervalMinutesSession and it is not null "); // Not executing 
			intervalMinutes = intervalMinutesSession;
		}

		let Username = Resources["CurrentSessionInfo"].GetCurrentUser();
		let dataSession = allSession.MachineParameters;
		let allData = dataSession;
        logger.info(loggerBeginning + "Line 36 Machine Parameters are"+allData.length);

		let isThereColor = false;
		let isThereLine = false;
		let index = 99;
		for (let i = 0; i < allData.length; i++) {
			//  if (allData[i].Color == ("color" + String(colorID))) {      //Original (Need to check issue with data type) 
            //  if (allData[i].Color == "color" + (i+1)) {
                if (allData[i].Color == ("color" + allData[i].colorID)) {  // Working 
            //    logger.info(loggerBeginning +" Line 38 inside if where color matches with colorID " +allData[i].colorID);
				isThereColor = true;
				isThereLine = true;
				index = i;
				break;
			}
		}

		let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.MachineParametersData.DS"
		});

		if (isThereColor == true && isThereLine == true) {
          //  logger.info(loggerBeginning + " Line 52 inside if where we get color and line and we call GetRealTimeMachineParameters ");
          //  logger.info(loggerBeginning + " Line 60 parameter values for GetRealTimeMachineParameters are machine id is  "+allData[index].MachineId+" parameter id is  "+parseInt(allData[index].ParameterId));
          //  logger.info(loggerBeginning + " Line 61 start time is "+startTime+" Interval minutes are "+intervalMinutes+" "); 
            let parameterData = me.GetRealTimeMachineParameters({
				end_date: endTime /* DATETIME */ ,
				machine_id: allData[index].MachineId /* STRING */ ,
				parameter_id: parseInt(allData[index].ParameterId) /* NUMBER */ ,
				start_date: startTime /* DATETIME */ ,
				intervalMinutes: intervalMinutes
			});
			if (parameterData.length > 0) {
              //  logger.info(loggerBeginning + " Line 61 inside if where we get parameterData is greater than 1 ");
				data.AddRow({
					machine_id: allData[index].MachineId, // STRING
					parameter_id: parseInt(allData[index].ParameterId), // INTEGER
					parameter_name: allData[index].ParameterName, // STRING
					parameter_value: parameterData[0].parameter_value.toFixed(1), // NUMBER
					timestamp: startTime // DATETIME
				});
			}
			for (let i = 0; i < parameterData.length; i++) {
            //   logger.info(loggerBeginning + " Line 71 add machine id ");
				data.AddRow({
					machine_id: allData[index].MachineId, // STRING
					parameter_id: parseInt(allData[index].ParameterId), // INTEGER
					parameter_name: allData[index].ParameterName, // STRING
					parameter_value: parameterData[i].parameter_value.toFixed(1), // NUMBER
					timestamp: parameterData[i].timestamp // DATETIME
				});
			}
			if (data.length < 1) {
             //   logger.info(loggerBeginning + " Line 81 in if when data.length is less than 1 which is 0 ");
				data.AddRow({
					machine_id: allData[index].MachineId, // STRING
					parameter_id: parseInt(allData[index].ParameterId), // INTEGER
					parameter_name: allData[index].ParameterName, // STRING
					parameter_value: 0, // NUMBER
					timestamp: startTime // DATETIME
				});
			}
		} else {
         // logger.info(loggerBeginning + " Line 91 not good in else when no line or color is present ");
			data.AddRow({
				machine_id: "", // STRING
				parameter_id: 0, // INTEGER
				parameter_name: "", // STRING
