/*
 * @name GetParameterFilterForTree
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param treeData (INFOTABLE : HPMC.AddOn.RTMP.Tree.DS)
 * @return (INFOTABLE : HPMC.AddOn.RTMP.DropdownData.DS)
 *
 * return filter for machine parameters
 */

var result;
var loggerBeginning = "[" + me.name + ":GetParameterFilterForTree]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to get filter for machine parameters");

		let parameterNameList = [];
		let parameterIdList = [];
		for (let i = 0; i < treeData.length; i++) {
			if (treeData[i].parentName != "root") {
				if (parameterNameList.includes(String(treeData[i].childName)) == false) {
					parameterNameList.push(String(treeData[i].childName));
					parameterIdList.push(String(treeData[i].childID));
				}
			}
		}
		let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.DropdownData.DS"
		});
		for (let i = 0; i < parameterNameList.length; i++) {
			let currentLanguage = Resources['CurrentSessionInfo'].GetCurrentUserLanguage();
			let title = Resources['RuntimeLocalizationFunctions'].GetEffectiveTokenForLanguage({
				language: currentLanguage /* STRING */ ,
				token: "HPMC.Parameter." + parameterNameList[i].split(" ").join("") /* STRING */ ,
			});
			data.AddRow({
				dropdown_id: parameterIdList[i], // STRING [Primary Key]
				dropdown_value: parameterNameList[i], // STRING
				dropdown_display: title // STRING
			});
		}
		let localInfoTable = data;
		let sort = {
			name: "dropdown_display",
			ascending: true
		};
		localInfoTable.Sort(sort);
		data = localInfoTable;

		result = data;

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot get filter for machine parameters" + " " + "Exception : " + error);
		let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.DropdownData.DS"
		});
		data.AddRow({
			dropdown_id: "0", // STRING [Primary Key]
			dropdown_value: "0", // STRING
			dropdown_display: "0" // STRING
		});
		result = data;
	}
}());


/*
 * @name GetParameterLowerBoundData
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param startTime (DATETIME)
 * @param endTime (DATETIME)
 * @return (INFOTABLE : HPMC.AddOn.RTMP.LineChart.DS)
 *
 * return lower bound data for one line chart
 */

var result;
var loggerBeginning = "[" + me.name + ":GetParameterLowerBoundData]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to get lower bound data for one line chart");

		let Username = Resources["CurrentSessionInfo"].GetCurrentUser();

		let allSession = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
		let dataSession = allSession.MachineParameters;
		let allData = dataSession;


		let isThereColor = false;
		let isThereLine = false;
		let index = 99;
		for (let i = 0; i < allData.length; i++) {
			isThereColor = true;
			if (allData[i].Boundaries == true) {
				isThereLine = true;
				index = i;
				break;
			}
		}

		let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.LineChart.DS"
		});

		if (isThereColor == true && isThereLine == true) {
			let boundariesData = me.GetUpperLowerBound({
				machine_id: allData[index].MachineId /* STRING */ ,
				parameter_id: parseInt(allData[index].ParameterId) /* NUMBER */
			});
			if (boundariesData.lower_bound != undefined) {
				data.AddRow({
					"datetime": startTime,
					"value": boundariesData.lower_bound
				});
				data.AddRow({
					"datetime": endTime,
					"value": boundariesData.lower_bound
				});
			} else {
				data.AddRow({
					"datetime": new Date(Number(startTime) - (10 * 60 * 60 * 1000)),
					"value": 0
				});
			}
		} else {
			data.AddRow({
				"datetime": new Date(Number(startTime) - (10 * 60 * 60 * 1000)),
				"value": 0
			});
		}
		result = data;

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot get lower bound data for one line chart" + " " + "Exception : " + error);
	}
}());


