/*
 * @name GetRawDataForExport
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param startTime (DATETIME)
 * @param endTime (DATETIME)
 * @param timezoneOffset (NUMBER)
 * @return (INFOTABLE : HPMC.AddOn.RTMP.RawData.Export.DS)
 *
 * return raw data for export
 */

var result;
var loggerBeginning = "[" + me.name + ":GetRawDataForExport]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to get raw data for export");

		let Username = Resources["CurrentSessionInfo"].GetCurrentUser();
		let allSession = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
		let dataSession = allSession.MachineParameters;
		let allData = dataSession;

		let machineIdList = "''";
		let parameterIdList = "0";
		for (let i = 0; i < allData.length; i++) {
			if (allData[i].MachineId != "") {
				machineIdList += ",'" + allData[i].MachineId + "'";
				parameterIdList += "," + allData[i].ParameterId;
			}
		}

		let data = me.ExportMachineParameterData({
			end_date: endTime /* STRING */ ,
			parameterIdList: parameterIdList /* STRING */ ,
			machineIdList: machineIdList /* STRING */ ,
			start_date: startTime /* DATETIME */
		});

		let result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.RawData.Export.DS"
		});

		for (let i = 0; i < data.length; i++) {
			let currentLanguage = Resources['CurrentSessionInfo'].GetCurrentUserLanguage();
			let title = Resources['RuntimeLocalizationFunctions'].GetEffectiveTokenForLanguage({
				language: currentLanguage /* STRING */ ,
				token: "HPMC.Parameter." + data[i].parameter_name.split(" ").join("") /* STRING */ ,
			});
			result.AddRow({
				no: i + 1,
				loc_id: data[i].loc_id, // NUMBER
				uc_id: data[i].uc_id, // NUMBER
				machine_id: data[i].machine_id, // STRING
				parameter_id: data[i].parameter_id, // NUMBER
				parameter_name: title, // STRING
				parameter_value: data[i].parameter_value, // NUMBER
				timestamp: new Date(Number(data[i].timestamp) + (timezoneOffset * 60 * 60 * 1000)) // DATETIME
			});
		}

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot get raw data for export" + " " + "Exception : " + error);
	}
}());


