var loggerBeginning = "[" + me.name + ":GetRTMPDataTable]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + " Line 16 Service to get machine parameters session");
		let Username = Resources["CurrentSessionInfo"].GetCurrentUser();
		let allSession = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
        let dataSession = allSession.MachineParameters;
		let allData = dataSession;

        let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.Table.DS"
		});
   		logger.info(loggerBeginning + "Line 31");

        for (let i = 0; i < allData.length; i++) {
            logger.info(loggerBeginning + " Created new lineData InfoTable for index: " + i);
			let lineData = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
				infoTableName: "InfoTable",
				dataShapeName: "HPMC.AddOn.RTMP.DropdownData.DS"
			});
             if (allData[i].Line == "Line 1") {
                    logger.info(loggerBeginning + " Line 43");    
                    lineData.AddRow({
                        dropdown_id: "RTMPLine1", // STRING [Primary Key]
                        dropdown_value: "Line 1" // STRING
              });
             }else if (allData[i].Line == "Line 2") {
                      logger.info(loggerBeginning + " Line 50");   
                    lineData.AddRow({
                        dropdown_id: "RTMPLine2", // STRING [Primary Key]
                        dropdown_value: "Line 2" // STRING
                    });
                }
              if (allData[i].MachineName != "") {
                     logger.info(loggerBeginning + " Line 58 adding machine data");    
                    data.AddRow({
                        colorID: allData[i].colorID,
                        Location: allData[i].Location, // STRING
                        MachineName: allData[i].MachineName, // STRING
                        ParameterName: allData[i].ParameterName, // STRING
                        Line: lineData, // INFOTABLE
                        Color: allData[i].Color, // STRING [Primary Key]
                        Boundaries: allData[i].Boundaries,
                        BoundariesDisable: allData[i].BoundariesDisable,
                        ParameterDesc: allData[i].ParameterDesc // STRING
                    });
                }
		}
  	    result = data;
	logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot get machine parameters session" + " " + "Exception : " + error);
	}
}());


