/*
 * @name GetRTMPTick
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param timeCategory (STRING)
 * @param startTime (DATETIME)
 * @param endTime (DATETIME)
 * @param timezoneOffset (NUMBER)
 * @return (INFOTABLE : HPMC.AddOn.RTMP.Tick.DS)
 *
 * return tick hour and minute
 */

var result;
var loggerBeginning = "[" + me.name + ":GetRTMPTick]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to get tick hour and minute");

		let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.Tick.DS"
		});
		startTime = new Date(Number(startTime) + (timezoneOffset * 60 * 60 * 1000));
		endTime = new Date(Number(endTime) + (timezoneOffset * 60 * 60 * 1000));
		let tickLabel = ["", "", "", "", "", "", "", "", "", "", "", "", ""];

		let currentTime = new Date(Number(startTime));
		let i = 0;
		while (Number(currentTime) < Number(endTime)) {
			let hour = String(currentTime.getHours());
			if (Number(hour) < 10) {
				hour = "0" + hour;
			}
			let minute = String(currentTime.getMinutes());
			if (Number(minute) < 10) {
				minute = "0" + minute;
			}
			tickLabel[i] = hour + ":" + minute;
			if (timeCategory == "last 30 minutes") {
				currentTime = new Date(Number(currentTime) + (5 * 60 * 1000));
				i += 2;
			} else {
				i += 1;
				if (timeCategory == "last 1 hour") {
					currentTime = new Date(Number(currentTime) + (5 * 60 * 1000));
				} else if (timeCategory == "last 3 hours") {
					currentTime = new Date(Number(currentTime) + (15 * 60 * 1000));
				} else if (timeCategory == "last 6 hours") {
					currentTime = new Date(Number(currentTime) + (30 * 60 * 1000));
				} else if (timeCategory == "last 12 hours") {
					currentTime = new Date(Number(currentTime) + (60 * 60 * 1000));
				} else if (timeCategory == "last 24 hours") {
					currentTime = new Date(Number(currentTime) + (2 * 60 * 60 * 1000));
				} else {
					let difference = dateDifference(endTime, startTime) / 12;
					currentTime = new Date(Number(currentTime) + (difference));
				}
			}
		}
		let hour = String(currentTime.getHours());
		if (Number(hour) < 10) {
			hour = "0" + hour;
		}
		let minute = String(currentTime.getMinutes());
		if (Number(minute) < 10) {
			minute = "0" + minute;
		}
		tickLabel[i] = hour + ":" + minute;

		data.AddRow({
			label1: tickLabel[0], // STRING
			label2: tickLabel[1], // STRING
			label3: tickLabel[2], // STRING
			label4: tickLabel[3], // STRING
			label5: tickLabel[4], // STRING
			label6: tickLabel[5], // STRING
			label7: tickLabel[6], // STRING
			label8: tickLabel[7], // STRING
			label9: tickLabel[8], // STRING
			label10: tickLabel[9], // STRING
			label11: tickLabel[10], // STRING
			label12: tickLabel[11], // STRING
			label13: tickLabel[12] // STRING
		});

		result = data;

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot get tick hour and minute" + " " + "Exception : " + error);
	}
}());


/*
 * @name GetRTMPTickDate
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param timeCategory (STRING)
 * @param startTime (DATETIME)
 * @param endTime (DATETIME)
 * @param timezoneOffset (NUMBER)
 * @return (INFOTABLE : HPMC.AddOn.RTMP.Tick.DS)
 *
 * return tick dd/mm/yy
 */

var result;
var loggerBeginning = "[" + me.name + ":GetRTMPTickDate]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to get tick dd/mm/yy");

		let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.Tick.DS"
		});
		startTime = new Date(Number(startTime) + (timezoneOffset * 60 * 60 * 1000));
		endTime = new Date(Number(endTime) + (timezoneOffset * 60 * 60 * 1000));
		let tickLabel = ["", "", "", "", "", "", "", "", "", "", "", "", ""];

		let currentTime = new Date(Number(startTime));
		let lastDay = 99;
		let i = 0;
		while (Number(currentTime) < Number(endTime)) {
			let date = String(currentTime.getDate());
			if (Number(date) < 10) {
				date = "0" + date;
			}
			let month = String(currentTime.getMonth() + 1);
			if (Number(month) < 10) {
				month = "0" + month;
			}
			let year = String(currentTime.getFullYear());
			year = year.slice(2, 4);
			if (lastDay != currentTime.getDay()) {
				tickLabel[i] = date + "/" + month + "/" + year;
				lastDay = currentTime.getDay();
			}
			if (timeCategory == "last 30 minutes") {
				currentTime = new Date(Number(currentTime) + (5 * 60 * 1000));
				i += 2;
			} else {
				i += 1;
				if (timeCategory == "last 1 hour") {
					currentTime = new Date(Number(currentTime) + (5 * 60 * 1000));
				} else if (timeCategory == "last 3 hours") {
					currentTime = new Date(Number(currentTime) + (15 * 60 * 1000));
				} else if (timeCategory == "last 6 hours") {
					currentTime = new Date(Number(currentTime) + (30 * 60 * 1000));
				} else if (timeCategory == "last 12 hours") {
					currentTime = new Date(Number(currentTime) + (60 * 60 * 1000));
				} else if (timeCategory == "last 24 hours") {
					currentTime = new Date(Number(currentTime) + (2 * 60 * 60 * 1000));
				} else {
					let difference = dateDifference(endTime, startTime) / 12;
					currentTime = new Date(Number(currentTime) + (difference));
				}
			}
		}

		let date = String(currentTime.getDate());
		if (Number(date) < 10) {
			date = "0" + date;
		}
		let month = String(currentTime.getMonth() + 1);
		if (Number(month) < 10) {
			month = "0" + month;
		}
		let year = String(currentTime.getFullYear());
		year = year.slice(2, 4);
		if (lastDay != currentTime.getDay()) {
			tickLabel[i] = date + "/" + month + "/" + year;
			lastDay = currentTime.getDay();
		}

		data.AddRow({
			label1: tickLabel[0], // STRING
			label2: tickLabel[1], // STRING
			label3: tickLabel[2], // STRING
			label4: tickLabel[3], // STRING
			label5: tickLabel[4], // STRING
			label6: tickLabel[5], // STRING
			label7: tickLabel[6], // STRING
			label8: tickLabel[7], // STRING
			label9: tickLabel[8], // STRING
			label10: tickLabel[9], // STRING
			label11: tickLabel[10], // STRING
			label12: tickLabel[11], // STRING
			label13: tickLabel[12] // STRING
		});

		result = data;

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot get tick dd/mm/yy" + " " + "Exception : " + error);
	}
}());


