/*
 * @name GetStatusMessageMaxDaterange
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @return (STRING)
 *
 * return status message when date range is out of limit
 */

var result;
var loggerBeginning = "[" + me.name + ":GetStatusMessageMaxDaterange]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to get status message when date range is out of limit");

		result = "Date range is too long, select again start date and end date!";
		let allSession = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
		let dataSession = allSession.MachineParameters;
		let allData = dataSession;
		let maxMinuteRange = me.maxMinuteRange / allData.length;
		let maxDays = Math.floor(maxMinuteRange / (60 * 24));
		let maxHours = Math.floor((maxMinuteRange - (maxDays * 60 * 24)) / 60);
		let maxMinutes = Math.floor(maxMinuteRange - (maxDays * 60 * 24) - (maxHours * 60));
		result += " maximum range is " + maxDays + " days " + maxHours + " hours " + maxMinutes + " minutes";

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot get status message when date range is out of limit" + " " + "Exception : " + error);
	}
}());


