        TileIcon:  "HPMC.Core..Icon.Media", // STRING
        OpenInNewWindow: false, // BOOLEAN
        LocalizedTooltip: "[[HPMC.InfoMsg.]]", // TEXT
        LocalizedLabel: "[[HPMC.]]", // TEXT
        LocalizedDescription: undefined, // TEXT
        Section: undefined, // STRING
        ModuleManager: me.name // THINGNAME
    });

    Things["HPMC.Core.Manager"].SetConfigurationTableRows({
      values: navigationEntry /* INFOTABLE */,
      persistent: true /* BOOLEAN {"defaultValue":true} */,
      tableName: "NavigationEntries" /* STRING */
    });
};
const addModuleToAdministrationMenu = () => {
    try {
        const isAdminManagerAvailable = Things[Things["HPMC.Core.Manager"].GetManagerEntity({ moduleName: "Admin" })].name;
    } catch (err) {
        return;
    }
    const administrationEntry = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
        dataShapeName: "HPMC.Core.Administration.Menu.DS"
    });
    administrationEntry.AddRow({
        isDefault: false, // BOOLEAN
        linkType: "Menu", // STRING
        menuId: undefined, // STRING
        parentMenuId: "Main", // STRING
        title: undefined, // STRING
        entityId: undefined // NUMBER [Primary Key]
    });
    administrationEntry.AddRow({
        isDefault: false, // BOOLEAN
        targetMashup: undefined, // STRING
        linkType: "Mashup", // STRING
        menuId: undefined, // STRING
        parentMenuId: undefined, // STRING
        title: undefined, // STRING
        entityId: undefined // NUMBER [Primary Key]
    });

    Things[Things["HPMC.Core.Manager"].GetManagerEntity({moduleName: "Admin" })].SetConfigurationTableRows({
      values: administrationEntry /* INFOTABLE */,
      persistent: true /* BOOLEAN {"defaultValue":true} */,
      tableName: "menuEntities" /* STRING */
    });
};

/* **************************** Constants **************************** */
// Extract the module name from the manager template naming scheme. I.e.
const ORGANIZATION_NAME = "HPMC.Voestalpine.Orga";
const USER_GROUP = getModuleUserGroupName();
const MANAGER_THING = me.name;

// **************************** INSERT CUSTOM LOGIC HERE **************************** //
let result = false;
try {
    // Create component usergroup and add it as member to the Core usergroup
    if (!Groups[USER_GROUP]) {
        Resources["EntityServices"].CreateGroup({
            name: USER_GROUP /* STRING */,
            description: "Core usergroup that contains the usergroup for each HPMC module." /* STRING */,
            projectName: "HPMC.DynamicData" /* PROJECTNAME */,
            tags: undefined /* TAGS */
        });
    }
    Groups["HPMC.Core.Users.UG"].AddMember({
        member: USER_GROUP /* STRING */,
        type: "Group" /* STRING */
    });
  /* **************************** Set permissions for project entities **************************** */
    /* THINGS */
    addVisibilityPermission(Things, MANAGER_THING, ORGANIZATION_NAME, "Organization");
    addRunTimePermission(Things, MANAGER_THING, USER_GROUP, "*", "PropertyRead", "Group");
    addRunTimePermission(Things, MANAGER_THING, USER_GROUP, "*", "ServiceInvoke", "Group");

    //Add module to Navigation Menu
     addModuleToNavigationMenu();

    //Add module to Administration Menu
    // addModuleToAdministrationMenu();

    /* MASHUPS, STYLE DEFINITION, STYLE THEMES, DATA SHAPES, MEDIA OF PROJECT*/
    let entities = Projects[me.GetProjectName()].GetEntities();
    const entityTypeArr = ["Mashup", "DataShape", "MediaEntity", "StateDefinition", "StyleDefinition", "StyleTheme"];

    entities = Resources["InfoTableFunctions"].Query({
        t: entities /* INFOTABLE */,
        query: { filters: { type: "IN", fieldName: "type", values: entityTypeArr } } /* QUERY */
    });
    entities.rows.toArray().forEach((row) => {
        const entityType = row.type === "MediaEntity" ? MediaEntities : eval(row.type + "s");
        addVisibilityPermission(entityType, row.name, ORGANIZATION_NAME, "Organization");
        addDesignTimePermission(entityType, row.name, USER_GROUP, "Read", "Group");
    });

    result = true;
} catch (err) {
    logger.error(me.name + ".InitializeModule: " + err.message + " - Line#" + err.lineNumber);
    Subsystems["PlatformSubsystem"].DeleteGhostEntities({
        deleteGhostEntitiesInAllInstances: true /* BOOLEAN {"defaultValue":false} */
    });
}


