/*
 * This service is created to Trigger emails when the parameter value is breached
 * @name TriggerEmail
 * @date 24.06.2025
 * @author Atharva Mahabal
 */

let emailLogTable1 = Things["HPMC.AddOn.RTMP.Manager"].TriggeredEmailsLog;
let emailLogTable = Resources["InfoTableFunctions"].CreateInfoTable({ infoTableName: "EmailTriggerLog" });

// Add fields once
emailLogTable.AddField({ name: "Timestamp", baseType: "DATETIME" });
emailLogTable.AddField({ name: "MachineId", baseType: "STRING" });
emailLogTable.AddField({ name: "ParameterId", baseType: "NUMBER" });
emailLogTable.AddField({ name: "EmailSentTo", baseType: "STRING" });
emailLogTable.AddField({ name: "UpperBound", baseType: "NUMBER" });
emailLogTable.AddField({ name: "LowerBound", baseType: "NUMBER" });
emailLogTable.AddField({ name: "ParameterValue", baseType: "NUMBER" });

let machineInfo = Things["HPMC.AddOn.RTMP.Manager"].MachineEmailAlertLog;

if (machineInfo && machineInfo.rows.length > 0) {
    let rows = machineInfo.rows.toArray();

    for (let i = 0; i < rows.length; i++) {
        let row = rows[i];
        let breachType = null;

        if (row.parameterValue > row.UpperBound) {
            breachType = "Upper";
        } else if (row.parameterValue < row.LowerBound) {
            breachType = "Lower";
        }

        if (breachType !== null) {
            // Log the breach
            let logRow = {
                Timestamp: new Date(),
                MachineId: row.MachineId,
                ParameterId: row.ParameterId,
                EmailSentTo: row.email,
                UpperBound: row.UpperBound,
                LowerBound: row.LowerBound,
                ParameterValue: row.parameterValue
            };
            // emailLogTable.AddRow(logRow);
            // emailLogTable1.AddRow(logRow);

            // Send Email
            let subject = breachType === "Upper" ? "Parameter Current Value Greater than Upper Limit" : "Parameter Current Value Lower than Lower Limit";

            let body =
                "Test: Kindly check machine <b>" +
                row.MachineId +
                "</b>, parameter ID <b>" +
                row.ParameterId +
                "</b>. Current value is <b>" +
                row.parameterValue +
                "</b>. " +
                (breachType === "Upper"
                    ? "Upper limit is <b>" + row.UpperBound + "</b>. Upper limit breached."
                    : "Lower limit is <b>" + row.LowerBound + "</b>. Lower limit breached.");

            Things["HPMC.Addon.RTMP.Management.MailExtension.Helper"].SendMessage({
                cc: "atharva.mahabal@voestalpine.com",
                bcc: undefined,
                subject: subject,
                from: "CLC_vHPMP@voestalpine.com",
                to: row.email,
                body: body
            });
        }
    }
}

result = emailLogTable1;


/*
 * @name UpdateBoundariesRTMPV2
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @param Color (STRING)
 * @param Line (INFOTABLE : HPMC.AddOn.DropdownData.DS)
 * @param Boundaries (BOOLEAN)
 * @return (INFOTABLE : HPMC.AddOn.RTMP.Table.ForDataTable.DS)
 *
 * return new machine parameters session after update boundaries
 */

var result;
var loggerBeginning = "[" + me.name + ":UpdateBoundariesRTMPV2]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to get new machine parameters session after update boundaries");

		let Username = Resources["CurrentSessionInfo"].GetCurrentUser();
		let allSession = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
		let dataSession = allSession.MachineParameters;
		let allData = dataSession;

		let changeLine = Line.dropdown_value;
		let change = true;
		let isThereBoundaries = false;

		let updatedData = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.Table.ForDataTable.DS"
		});
		try {
			if (isThereBoundaries == false) {
				if (change == true) {
					for (let i = 0; i < allData.length; i++) {
						if (allData[i].Username_Color == Username + "$" + Color) {
							updatedData.AddRow({
								colorID: allData[i].colorID,
								Location: allData[i].Location, // STRING
								MachineName: allData[i].MachineName, // STRING
								ParameterName: allData[i].ParameterName, // STRING
								MachineId: allData[i].MachineId,
								ParameterId: allData[i].ParameterId,
								Line: changeLine, // STRING
								Color: Color, // STRING [Primary Key]
								Boundaries: Boundaries,
								BoundariesDisable: allData[i].BoundariesDisable,
								ParameterDesc: allData[i].ParameterDesc, // STRING
								Username_Color: allData[i].Username_Color
							});
						} else {
							updatedData.AddRow({
								colorID: allData[i].colorID,
								Location: allData[i].Location, // STRING
								MachineName: allData[i].MachineName, // STRING
								ParameterName: allData[i].ParameterName, // STRING
								MachineId: allData[i].MachineId,
								ParameterId: allData[i].ParameterId,
								Line: allData[i].Line, // STRING
								Color: allData[i].Color, // STRING [Primary Key]
								Boundaries: allData[i].Boundaries,
								BoundariesDisable: allData[i].BoundariesDisable,
								ParameterDesc: allData[i].ParameterDesc, // STRING
								Username_Color: allData[i].Username_Color
							});
						}
					}
					result = updatedData;
				} else {
					result = allData;
				}

				let newAllData = updatedData;
				let boundariesCountLine1 = 0;
				let boundariesCountLine2 = 0;
				for (let i = 0; i < newAllData.length; i++) {
					if (newAllData[i].Line == "Line 1") {
						if (newAllData[i].Boundaries == true) {
							boundariesCountLine1 += 1;
						}
					}
					if (newAllData[i].Line == "Line 2") {
						if (newAllData[i].Boundaries == true) {
							boundariesCountLine2 += 1;
						}
					}
				}

				let BoundariesDisableLine1 = false;
				let BoundariesDisableLine2 = false;
				if (boundariesCountLine1 > 0) {
					BoundariesDisableLine1 = true;
				}
				if (boundariesCountLine2 > 0) {
					BoundariesDisableLine2 = true;
				}

				let updatedData2 = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
					infoTableName: "InfoTable",
					dataShapeName: "HPMC.AddOn.RTMP.Table.ForDataTable.DS"
				});

				for (let i = 0; i < newAllData.length; i++) {
					if (newAllData[i].Boundaries == false) {
						let BoundariesDisable;
						if (newAllData[i].Line == "Line 1") {
							BoundariesDisable = BoundariesDisableLine1;
						} else {
							BoundariesDisable = BoundariesDisableLine2;
						}
						updatedData2.AddRow({
							colorID: newAllData[i].colorID,
							Location: newAllData[i].Location, // STRING
							MachineName: newAllData[i].MachineName, // STRING
							ParameterName: newAllData[i].ParameterName, // STRING
							MachineId: newAllData[i].MachineId,
							ParameterId: newAllData[i].ParameterId,
							Line: newAllData[i].Line, // STRING
							Color: newAllData[i].Color, // STRING [Primary Key]
							Boundaries: newAllData[i].Boundaries,
							BoundariesDisable: BoundariesDisable,
							ParameterDesc: newAllData[i].ParameterDesc, // STRING
							Username_Color: newAllData[i].Username_Color
						});
					} else {
						updatedData2.AddRow({
							colorID: newAllData[i].colorID,
							Location: newAllData[i].Location, // STRING
							MachineName: newAllData[i].MachineName, // STRING
							ParameterName: newAllData[i].ParameterName, // STRING
							MachineId: newAllData[i].MachineId,
							ParameterId: newAllData[i].ParameterId,
							Line: newAllData[i].Line, // STRING
							Color: newAllData[i].Color, // STRING [Primary Key]
							Boundaries: newAllData[i].Boundaries,
							BoundariesDisable: newAllData[i].BoundariesDisable,
							ParameterDesc: newAllData[i].ParameterDesc, // STRING
							Username_Color: newAllData[i].Username_Color
						});
					}
				}
				result = updatedData2;
			}
		} catch (error) {
			result = allData;
		}

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot get new machine parameters session after update boundaries" + " " + "Exception : " + error);
	}
}());


