						updatedData2.AddRow({
							colorID: newAllData[i].colorID,
							Location: newAllData[i].Location, // STRING
							MachineName: newAllData[i].MachineName, // STRING
							ParameterName: newAllData[i].ParameterName, // STRING
							MachineId: newAllData[i].MachineId,
							ParameterId: newAllData[i].ParameterId,
							Line: newAllData[i].Line, // STRING
							Color: newAllData[i].Color, // STRING [Primary Key]
							Boundaries: newAllData[i].Boundaries,
							BoundariesDisable: newAllData[i].BoundariesDisable,
							ParameterDesc: newAllData[i].ParameterDesc, // STRING
							Username_Color: newAllData[i].Username_Color
						});
					}
				}
				result = updatedData2;
			} else {
				result = allData;
			}
		} else {
			result = allData;
		}

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot update line machine parameter" + " " + "Exception : " + error);
	}
}());


/*
