					Line: MachineParametersSession[i].Line, // STRING
					Boundaries: MachineParametersSession[i].Boundaries, // BOOLEAN
					BoundariesDisable: MachineParametersSession[i].BoundariesDisable, // BOOLEAN
					Color: MachineParametersSession[i].Color, // STRING
					ParameterDesc: MachineParametersSession[i].ParameterDesc, // STRING
					Username_Color: MachineParametersSession[i].Username_Color // STRING [Primary Key]
				});
			}
			let newIndex = MachineParameters1.colorID - 1;
			data[newIndex].Location = MachineParameters1.Location;
			data[newIndex].MachineId = MachineParameters1.MachineId;
			data[newIndex].MachineName = MachineParameters1.MachineName;
			data[newIndex].ParameterId = MachineParameters1.ParameterId;
			data[newIndex].ParameterName = MachineParameters1.ParameterName;
			data[newIndex].Line = MachineParameters1.Line;
			data[newIndex].Boundaries = MachineParameters1.Boundaries;
			data[newIndex].BoundariesDisable = MachineParameters1.BoundariesDisable;
			data[newIndex].Color = MachineParameters1.Color;
			data[newIndex].ParameterDesc = MachineParameters1.ParameterDesc;
			data[newIndex].Username_Color = MachineParameters1.Username_Color;
		} else if (indicator == 2) { // add 10 parameter
            logger.info(loggerBeginning + "Line 79 inside else if indicator == 2 ");
			data = MachineParameters2;
     		logger.info(loggerBeginning + "Line 83 in else if block MachineParameter2 length is in else if "+data.length); //checking Machine Parameter value in else if block  20 Feb/2025 Atharva Mahabal
            logger.info(loggerBeginning + " Adding and updating 10 parameters when indicator == 1");               		
     	} else if (indicator == 3) { // next 10 parameter
            logger.info(loggerBeginning + "Line 82 inside else if indicator == 3");
			data = MachineParameters3;
		} else if (indicator == 4) { // prev 10 parameter
            logger.info(loggerBeginning + "Line 85 inside else if indicator == 4 ");
			data = MachineParameters4;
		} else {
            logger.info(loggerBeginning + "Line 88 inside else ");
			data = MachineParametersSession;
		}
		result = data;

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot update machine parameters session" + " " + "Exception : " + error);
	}
}());


/*
 * @name UpdateParametersForEmail
 * @date 26.06.2025
 * @author Atharva Mahabal
 * @param intervalMinutes
 * @return infotable
 *
 * Execute "TriggerEmail" if values are changed 
 */


const now = new Date();
const startOfDay = new Date(now);
startOfDay.setHours(0, 0, 0, 0);

let currentEmailInfotable = Things["HPMC.AddOn.RTMP.Manager"].MachineEmailAlertLog; //Property in Thing where we have stored current value

let updatedTable = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
    infoTableName: "UpdatedEmailAlerts",
    dataShapeName: "HPMC.AddOn.RTMP.EmailDataFields.DS"
});

for (let i = 0; i < currentEmailInfotable.rows.length; i++) {
    let row = currentEmailInfotable.rows[i];

    if (!row.MachineId || !row.ParameterId) {
        logger.warn("Skipping row due to missing MachineId or ParameterId");
        continue;
    }

    let currentValue = row.parameterValue;

    //Below service calls a database service from where we get real time data 
    let dbResult = Things["HPMC.AddOn.RTMP.Manager"].GetRealTimeMachineParameters({
        start_date: now,
        end_date: now,
        intervalMinutes: intervalMinutes,
        machine_id: row.MachineId,
        parameter_id: row.ParameterId
    });

    //parameter_value is the current value 
    let dbValue = (dbResult.rows.length > 0 && dbResult.rows[0].parameter_value !== undefined) ? dbResult.rows[0].parameter_value : null;

    logger.info("Comparing values: current=" + currentValue + ", db=" + dbValue);

    let changed = (dbValue !== null && dbValue !== currentValue);

    // Create updatedRow from original row
    let updatedRow = {};
    for (let key in row) {
        updatedRow[key] = row[key];
    }
        logger.info("Value of changed is " +changed);
    if (changed) {
        updatedRow.parameter_value = dbValue;
        logger.info(" Data has changed from " + currentValue + " to " + dbValue);
        me.TriggerEmail();
    } else {
        logger.info(" Data has not changed: remains " + currentValue);
    }

    updatedTable.AddRow(updatedRow);  
}

    //  Update property only once at the end
    Things["HPMC.AddOn.RTMP.Manager"].MachineEmailAlertLog = updatedTable;
    result = updatedTable;


/*
 * @name ValidateMachineParametersChangesV2
 * @date 12.12.2022
 * @author Abdurraafi' Syauqy
 * @return (INFOTABLE : HPMC.AddOn.RTMP.MachineParametersValidator.DS)
 *
 * return validation of machine parameters changes
 */

var result;
var loggerBeginning = "[" + me.name + ":ValidateMachineParametersChangesV2]";

(function() {
	"use strict";
	try {
		logger.info(loggerBeginning + "Service to validate machine parameters changes");

		result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
			infoTableName: "InfoTable",
			dataShapeName: "HPMC.AddOn.RTMP.MachineParametersValidator.DS"
		});
		let allSession = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
		let MachineParameters = allSession.MachineParameters;
		let LastMachineParameters = allSession.LastMachineParameters;
		let DataChanged = "";
		let LineChanged = "";
		let BoundariesChanged = "";
		let FalseCountDataChanged = 0;
		let FalseCountLineChanged = 0;
		let FalseCountBoundariesChanged = 0;
		for (let i = 0; i < LastMachineParameters.length; i++) {
			if (MachineParameters[i].ParameterId != LastMachineParameters[i].ParameterId) {
				DataChanged += "true,";
				FalseCountDataChanged += 1;
			} else {
				DataChanged += "false,";
			}
			if (MachineParameters[i].Line != LastMachineParameters[i].Line && LastMachineParameters[i].Line != "" && MachineParameters[i].Line != "") {
				LineChanged += "true,";
				FalseCountLineChanged += 1;
			} else {
				LineChanged += "false,";
			}
			if (MachineParameters[i].Boundaries != LastMachineParameters[i].Boundaries) {
				BoundariesChanged += "true,";
				FalseCountBoundariesChanged += 1;
			} else {
				BoundariesChanged += "false,";
			}
		}

		if (FalseCountDataChanged == 0 && FalseCountLineChanged == 0 && FalseCountBoundariesChanged == 0) {
			result.AddRow({
				indicator: -99, // NUMBER
				MachineParameters: LastMachineParameters, // INFOTABLE
				DataChanged: DataChanged, // STRING
				LineChanged: LineChanged, // STRING
				BoundariesChanged: BoundariesChanged // STRING
			});
		} else {
			result.AddRow({
				indicator: 1, // NUMBER
				MachineParameters: MachineParameters, // INFOTABLE
				DataChanged: DataChanged, // STRING
				LineChanged: LineChanged, // STRING
				BoundariesChanged: BoundariesChanged // STRING
			});
		}

		logger.info(loggerBeginning + "Service Succes");
	} catch (error) {
		logger.error(loggerBeginning + " " + "Cannot validate machine parameters changes" + " " + "Exception : " + error);
	}
}());
